deploy.deploy-all.ps1:
# Auto-deploy script for project: SSH Endpoint Port MTU
# Generated by Overlay Network Config Orchestrator
#
# Usage:
#   .\deploy-all.ps1 -ArtifactsZip <path-to-artifacts.zip> [-Clean]    Deploy overlay
#   .\deploy-all.ps1 -Uninstall                                         Remove overlay
#
# Options:
#   -Clean      Remove ALL existing WireGuard interfaces (wg*) before deploying.
#   -Uninstall  Completely remove the overlay from all nodes via SSH.
#               No artifacts ZIP needed.

param(
    [string]$ArtifactsZip,

    [switch]$Clean,

    [switch]$Uninstall
)

$ErrorActionPreference = "Continue"

if (-not $Uninstall -and [string]::IsNullOrEmpty($ArtifactsZip)) {
    Write-Host "Usage: .\deploy-all.ps1 -ArtifactsZip <path> [-Clean]"
    Write-Host "       .\deploy-all.ps1 -Uninstall"
    exit 1
}

$WorkDir = $null

if (-not [string]::IsNullOrEmpty($ArtifactsZip)) {
    if (-not (Test-Path $ArtifactsZip)) {
        Write-Error "File not found: $ArtifactsZip"
        exit 1
    }

    # Extract to temp
    $WorkDir = Join-Path ([System.IO.Path]::GetTempPath()) ("overlay-deploy-" + [System.Guid]::NewGuid().ToString("N").Substring(0,8))
    New-Item -ItemType Directory -Path $WorkDir -Force | Out-Null
}

# Clean script sent to remote via stdin (single-quoted — no PS expansion)
$CleanScript = 'for iface in $(ip -o link show type wireguard 2>/dev/null | awk -F: ''{print $2}'' | tr -d " "); do wg-quick down "$iface" 2>/dev/null || ip link del "$iface" 2>/dev/null || true; done; rm -f /etc/wireguard/wg*.conf; nft delete table inet overlay-snat 2>/dev/null || true; iptables-save -t nat 2>/dev/null | grep -E ''^-A POSTROUTING '' | grep -F -- ''-j SNAT'' | grep -F -- ''-o wg-+'' | while IFS= read -r _snat_rule; do _snat_del="${_snat_rule/#-A/-D}"; iptables -t nat $_snat_del 2>/dev/null || true; done || true; systemctl disable overlay-snat.service 2>/dev/null || true; rm -f /etc/systemd/system/overlay-snat.service'

try {
    if ($WorkDir) {
        Write-Host "Extracting artifacts..."
        Expand-Archive -Path $ArtifactsZip -DestinationPath $WorkDir -Force
    }

    if ($Uninstall) {
        Write-Host ""
        Write-Host "*** UNINSTALL MODE — overlay will be removed from all nodes ***" -ForegroundColor Yellow
        Write-Host ""
    }

    $Failed = 0
    $Skipped = 0
    $Success = 0

    Write-Host ""
    if ($Uninstall) {
        Write-Host ("=== Uninstalling from " + "router-a" + " (" + "prod-router-a" + ") ===")
        $sshTest = & ssh "prod-router-a" "echo ok" 2>&1
        if ($LASTEXITCODE -ne 0) {
            Write-Host ("  ERROR: SSH connection to " + "router-a" + " failed.") -ForegroundColor Red
            $Failed++
        } else {
            $uninstallScript = @'
set -uo pipefail
echo '[Stage 1/4] Stopping WireGuard interfaces on ''router-a''...'
wg-quick down wg-router-b 2>/dev/null || true
systemctl disable wg-quick@wg-router-b 2>/dev/null || true
rm -f /etc/wireguard/wg-router-b.conf
wg-quick down wg-client-a 2>/dev/null || true
systemctl disable wg-quick@wg-client-a 2>/dev/null || true
rm -f /etc/wireguard/wg-client-a.conf
for _i in $(wg show interfaces 2>/dev/null); do wg-quick down "$_i" 2>/dev/null || true; systemctl disable "wg-quick@$_i" 2>/dev/null || true; done
rm -f /etc/wireguard/*.conf
echo '[Stage 2/4] Stopping Babel routing daemon on ''router-a''...'
systemctl stop babeld 2>/dev/null || true
systemctl disable babeld 2>/dev/null || true
rm -f /etc/babel/babeld.conf /etc/babeld.conf
rm -rf /etc/systemd/system/babeld.service.d
echo '[Stage 3/4] Removing overlay network configuration on ''router-a''...'
rm -f /etc/sysctl.d/99-overlay.conf
sysctl --system > /dev/null 2>&1 || true
nft delete table inet overlay-snat 2>/dev/null || true
iptables-save -t nat 2>/dev/null | grep -E '^-A POSTROUTING ' | grep -F -- '-j SNAT' | grep -F -- '-o wg-+' | while IFS= read -r _snat_rule; do _snat_del="${_snat_rule/#-A/-D}"; iptables -t nat $_snat_del 2>/dev/null || true; done || true
systemctl disable overlay-snat.service 2>/dev/null || true
rm -f /etc/systemd/system/overlay-snat.service
ip link del dummy0 2>/dev/null || true
systemctl disable overlay-dummy.service 2>/dev/null || true
rm -f /etc/systemd/system/overlay-dummy.service
echo '[Stage 4/4] Reloading systemd on ''router-a''...'
systemctl daemon-reload
echo 'Overlay removed from ''router-a''.'
'@
            $uninstallScript | & ssh "prod-router-a" sudo bash -s
            if ($LASTEXITCODE -ne 0) {
                Write-Host ("  ERROR: Uninstall failed on " + "router-a" + ".") -ForegroundColor Red
                $Failed++
            } else {
                Write-Host ("  SUCCESS: " + "router-a" + " uninstalled.")
                $Success++
            }
        }
    } else {
        Write-Host ("=== Deploying to " + "router-a" + " (" + "prod-router-a" + ") ===")
        $Installer = Join-Path $WorkDir "router-a.install.sh"
        if (-not (Test-Path $Installer)) {
            Write-Warning "Installer router-a.install.sh not found in archive, skipping."
            $Skipped++
        } else {
            $sshTest = & ssh "prod-router-a" "echo ok" 2>&1
            if ($LASTEXITCODE -ne 0) {
                Write-Host ("  ERROR: SSH connection to " + "router-a" + " failed.") -ForegroundColor Red
                $Failed++
            } else {
                if ($Clean) {
                    Write-Host ("  Cleaning existing WireGuard interfaces on " + "router-a" + "...")
                    $CleanScript | & ssh "prod-router-a" sudo bash -s 2>$null
                }

                & scp $Installer "prod-router-a:/tmp/router-a-install.sh"
                if ($LASTEXITCODE -ne 0) {
                    Write-Host ("  ERROR: SCP upload to " + "router-a" + " failed.") -ForegroundColor Red
                    $Failed++
                } else {
                    & ssh "prod-router-a" "sudo bash /tmp/router-a-install.sh && rm -f /tmp/router-a-install.sh"
                    if ($LASTEXITCODE -ne 0) {
                        Write-Host ("  ERROR: Installation script failed on " + "router-a" + " (exit code: $LASTEXITCODE).") -ForegroundColor Red
                        $Failed++
                    } else {
                        Write-Host ("  SUCCESS: " + "router-a" + " deployed.")
                        $Success++
                    }
                }
            }
        }
    }

    Write-Host ""
    if ($Uninstall) {
        Write-Host ("=== Uninstalling from " + "router-b" + " (" + "deploy@router-b.example.com" + ") ===")
        $sshTest = & ssh -p 2222 -i "~/keys/My Deploy Key.pem" "deploy@router-b.example.com" "echo ok" 2>&1
        if ($LASTEXITCODE -ne 0) {
            Write-Host ("  ERROR: SSH connection to " + "router-b" + " failed.") -ForegroundColor Red
            $Failed++
        } else {
            $uninstallScript = @'
set -uo pipefail
echo '[Stage 1/4] Stopping WireGuard interfaces on ''router-b''...'
wg-quick down wg-router-a 2>/dev/null || true
systemctl disable wg-quick@wg-router-a 2>/dev/null || true
rm -f /etc/wireguard/wg-router-a.conf
for _i in $(wg show interfaces 2>/dev/null); do wg-quick down "$_i" 2>/dev/null || true; systemctl disable "wg-quick@$_i" 2>/dev/null || true; done
rm -f /etc/wireguard/*.conf
echo '[Stage 2/4] Stopping Babel routing daemon on ''router-b''...'
systemctl stop babeld 2>/dev/null || true
systemctl disable babeld 2>/dev/null || true
rm -f /etc/babel/babeld.conf /etc/babeld.conf
rm -rf /etc/systemd/system/babeld.service.d
echo '[Stage 3/4] Removing overlay network configuration on ''router-b''...'
rm -f /etc/sysctl.d/99-overlay.conf
sysctl --system > /dev/null 2>&1 || true
nft delete table inet overlay-snat 2>/dev/null || true
iptables-save -t nat 2>/dev/null | grep -E '^-A POSTROUTING ' | grep -F -- '-j SNAT' | grep -F -- '-o wg-+' | while IFS= read -r _snat_rule; do _snat_del="${_snat_rule/#-A/-D}"; iptables -t nat $_snat_del 2>/dev/null || true; done || true
systemctl disable overlay-snat.service 2>/dev/null || true
rm -f /etc/systemd/system/overlay-snat.service
ip link del dummy0 2>/dev/null || true
systemctl disable overlay-dummy.service 2>/dev/null || true
rm -f /etc/systemd/system/overlay-dummy.service
echo '[Stage 4/4] Reloading systemd on ''router-b''...'
systemctl daemon-reload
echo 'Overlay removed from ''router-b''.'
'@
            $uninstallScript | & ssh -p 2222 -i "~/keys/My Deploy Key.pem" "deploy@router-b.example.com" sudo bash -s
            if ($LASTEXITCODE -ne 0) {
                Write-Host ("  ERROR: Uninstall failed on " + "router-b" + ".") -ForegroundColor Red
                $Failed++
            } else {
                Write-Host ("  SUCCESS: " + "router-b" + " uninstalled.")
                $Success++
            }
        }
    } else {
        Write-Host ("=== Deploying to " + "router-b" + " (" + "deploy@router-b.example.com" + ") ===")
        $Installer = Join-Path $WorkDir "router-b.install.sh"
        if (-not (Test-Path $Installer)) {
            Write-Warning "Installer router-b.install.sh not found in archive, skipping."
            $Skipped++
        } else {
            $sshTest = & ssh -p 2222 -i "~/keys/My Deploy Key.pem" "deploy@router-b.example.com" "echo ok" 2>&1
            if ($LASTEXITCODE -ne 0) {
                Write-Host ("  ERROR: SSH connection to " + "router-b" + " failed.") -ForegroundColor Red
                $Failed++
            } else {
                if ($Clean) {
                    Write-Host ("  Cleaning existing WireGuard interfaces on " + "router-b" + "...")
                    $CleanScript | & ssh -p 2222 -i "~/keys/My Deploy Key.pem" "deploy@router-b.example.com" sudo bash -s 2>$null
                }

                & scp -P 2222 -i "~/keys/My Deploy Key.pem" $Installer "deploy@router-b.example.com:/tmp/router-b-install.sh"
                if ($LASTEXITCODE -ne 0) {
                    Write-Host ("  ERROR: SCP upload to " + "router-b" + " failed.") -ForegroundColor Red
                    $Failed++
                } else {
                    & ssh -p 2222 -i "~/keys/My Deploy Key.pem" "deploy@router-b.example.com" "sudo bash /tmp/router-b-install.sh && rm -f /tmp/router-b-install.sh"
                    if ($LASTEXITCODE -ne 0) {
                        Write-Host ("  ERROR: Installation script failed on " + "router-b" + " (exit code: $LASTEXITCODE).") -ForegroundColor Red
                        $Failed++
                    } else {
                        Write-Host ("  SUCCESS: " + "router-b" + " deployed.")
                        $Success++
                    }
                }
            }
        }
    }

    Write-Host ""
    Write-Host ("=== " + "client-a" + ": SKIPPED (no SSH details configured) ===")
    $Skipped++

    Write-Host ""
    Write-Host "============================================================"
    if ($Uninstall) {
        Write-Host "  Uninstall Summary"
    } else {
        Write-Host "  Deploy Summary"
    }
    Write-Host "  Success: $Success  Skipped: $Skipped  Failed: $Failed"
    Write-Host "============================================================"

    if ($Failed -gt 0) {
        exit 1
    }
} finally {
    if ($WorkDir) { Remove-Item -Recurse -Force $WorkDir -ErrorAction SilentlyContinue }
}
